import 'dart:math' as math;
import 'dart:ui';

/// Replayable geometry for the 2D fractal minimap.
///
/// The widget paints a tiny overview and an indicator for the currently visible
/// renderer viewport. Keeping the coordinate math pure lets tests characterize
/// assumptions about zoom samples, minimap size, and renderer aspect ratio
/// without relying on a canvas paint pass.
final class MiniMapGeometry {
  static const double defaultZoom = 1.0;
  static const double minimumIndicatorDimension = 4.0;

  /// Fractal-plane span represented by the minimap overview on each axis.
  static const double overviewWorldSpan = 4.0;

  const MiniMapGeometry._();

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return defaultZoom;
    return zoom;
  }

  static Offset normalizePan(Offset pan) {
    return Offset(
      pan.dx.isFinite ? pan.dx : 0.0,
      pan.dy.isFinite ? pan.dy : 0.0,
    );
  }

  /// Maps an absolute fractal-plane pan center to minimap pixels.
  static Offset centerForPan({
    required Offset pan,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safePan = normalizePan(pan);
    return Offset(
      width / 2.0 + safePan.dx * width / overviewWorldSpan,
      height / 2.0 + safePan.dy * height / overviewWorldSpan,
    );
  }

  /// Inverse of [centerForPan] for tap-to-pan jumps.
  static Offset panForCenter({
    required Offset center,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safeCenter = Offset(
      center.dx.isFinite ? center.dx : width / 2.0,
      center.dy.isFinite ? center.dy : height / 2.0,
    );
    return Offset(
      (safeCenter.dx / width - 0.5) * overviewWorldSpan,
      (safeCenter.dy / height - 0.5) * overviewWorldSpan,
    );
  }

  static Rect viewportRect({
    required Offset pan,
    required double zoom,
    required Size minimapSize,
    required Size viewportSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Rect.zero;

    final safePan = normalizePan(pan);
    final safeZoom = normalizeZoom(zoom);
    final safeViewportSize = _positiveFiniteViewportSize(viewportSize);
    final viewportShortSide = math.min(
      safeViewportSize.width,
      safeViewportSize.height,
    );
    final viewportWidthScale = safeViewportSize.width / viewportShortSide;
    final viewportHeightScale = safeViewportSize.height / viewportShortSide;

    final baseViewportWidth = (2.0 / safeZoom) * (width / overviewWorldSpan);
    final baseViewportHeight = (2.0 / safeZoom) * (height / overviewWorldSpan);
    final center = centerForPan(pan: safePan, minimapSize: minimapSize);

    return Rect.fromCenter(
      center: center,
      width: _clampIndicatorDimension(
        baseViewportWidth * viewportWidthScale,
        width,
      ),
      height: _clampIndicatorDimension(
        baseViewportHeight * viewportHeightScale,
        height,
      ),
    );
  }

  static Offset panForTap({
    required Offset localPosition,
    required Size minimapSize,
    required double zoom,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    // Pan is an absolute fractal-plane center; zoom changes the viewport
    // indicator size, not which overview coordinate a tap selects.
    return panForCenter(center: localPosition, minimapSize: minimapSize);
  }

  static double _positiveFiniteOrZero(double value) {
    return value.isFinite && value > 0.0 ? value : 0.0;
  }

  static Size _positiveFiniteViewportSize(Size size) {
    if (_positiveFiniteOrZero(size.width) == 0.0 ||
        _positiveFiniteOrZero(size.height) == 0.0) {
      return const Size(1, 1);
    }
    return size;
  }

  static double _clampIndicatorDimension(double value, double extent) {
    final lower = math.min(minimumIndicatorDimension, extent);
    if (!value.isFinite || value <= 0.0) return lower;
    return value.clamp(lower, extent).toDouble();
  }
}

import 'dart:ui';

import 'package:flutter_fractals/features/minimap/geometry/minimap_geometry.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('MiniMapGeometry.viewportRect', () {
    test('preserves the rendered viewport aspect ratio', () {
      final rect = MiniMapGeometry.viewportRect(
        pan: Offset.zero,
        zoom: 2.0,
        minimapSize: const Size(240, 240),
        viewportSize: const Size(1600, 900),
      );

      expect(rect.center, const Offset(120, 120));
      expect(rect.width / rect.height, closeTo(16 / 9, 1e-9));
    });

    test('keeps square viewport dimensions compatible with legacy mapping', () {
      final rect = MiniMapGeometry.viewportRect(
        pan: const Offset(1, -1),
        zoom: 2.0,
        minimapSize: const Size(120, 120),
        viewportSize: const Size(600, 600),
      );

      expect(rect.center, const Offset(90, 30));
      expect(rect.width, 30);
      expect(rect.height, 30);
    });

    test('normalizes malformed zoom samples instead of producing NaN rects',
        () {
      final rect = MiniMapGeometry.viewportRect(
        pan: const Offset(double.nan, double.infinity),
        zoom: double.nan,
        minimapSize: const Size(120, 120),
        viewportSize: Size.zero,
      );

      expect(rect.center, const Offset(60, 60));
      expect(rect.width, 60);
      expect(rect.height, 60);
    });
  });

  group('MiniMapGeometry.panForTap', () {
    test('is the inverse of viewport center mapping', () {
      const minimapSize = Size(120, 120);
      const viewportSize = Size(600, 600);
      const tap = Offset(120, 0);

      for (final zoom in [0.5, 1.0, 2.0, 8.0]) {
        final pan = MiniMapGeometry.panForTap(
          localPosition: tap,
          minimapSize: minimapSize,
          zoom: zoom,
        );
        final rect = MiniMapGeometry.viewportRect(
          pan: pan,
          zoom: zoom,
          minimapSize: minimapSize,
          viewportSize: viewportSize,
        );

        expect(rect.center.dx, closeTo(tap.dx, 1e-9), reason: 'zoom=$zoom');
        expect(rect.center.dy, closeTo(tap.dy, 1e-9), reason: 'zoom=$zoom');
      }
    });

    test('maps taps to absolute minimap coordinates independent of zoom', () {
      final zoomedOut = MiniMapGeometry.panForTap(
        localPosition: const Offset(120, 0),
        minimapSize: const Size(120, 120),
        zoom: 0.5,
      );
      final zoomedIn = MiniMapGeometry.panForTap(
        localPosition: const Offset(120, 0),
        minimapSize: const Size(120, 120),
        zoom: 8.0,
      );

      expect(zoomedOut, const Offset(2.0, -2.0));
      expect(zoomedIn, zoomedOut);
    });
  });
}

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/minimap/geometry/minimap_geometry.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:provider/provider.dart';
import 'package:vector_math/vector_math.dart' as vm;

/// A minimap overlay showing the current viewport position within a fractal.
class FractalMiniMap extends StatelessWidget {
  final Size viewportSize;
  final double size;
  final bool show3DIndicator;

  const FractalMiniMap({
    super.key,
    required this.viewportSize,
    this.size = 120,
    this.show3DIndicator = true,
  });

  @override
  Widget build(BuildContext context) {
    return Consumer<FractalController>(
      builder: (context, controller, _) {
        final viewState = controller.view;
        final is3D = controller.module.dimension == FractalDimension.threeD;

        if (is3D && show3DIndicator) {
          // For 3D fractals, show zoom indicator only
          return _ZoomIndicator(zoom: viewState.zoom);
        }

        return GestureDetector(
          onTapDown: (details) =>
              _handleTap(context, controller, details.localPosition),
          onPanUpdate: (details) =>
              _handleTap(context, controller, details.localPosition),
          child: Container(
            width: size,
            height: size,
            decoration: BoxDecoration(
              color: Colors.black54,
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: Colors.white24),
            ),
            child: Stack(
              children: [
                // Grid lines
                CustomPaint(
                  size: Size(size, size),
                  painter: _GridPainter(),
                ),
                // Viewport rectangle
                CustomPaint(
                  size: Size(size, size),
                  painter: _ViewportPainter(
                    pan: Offset(viewState.pan.x, viewState.pan.y),
                    zoom: viewState.zoom,
                    viewportSize: viewportSize,
                  ),
                ),
                // Center dot
                Center(
                  child: Container(
                    width: 6,
                    height: 6,
                    decoration: BoxDecoration(
                      color: Colors.red,
                      shape: BoxShape.circle,
                      border: Border.all(color: Colors.white, width: 1),
                    ),
                  ),
                ),
                // Zoom indicator
                Positioned(
                  bottom: 4,
                  left: 0,
                  right: 0,
                  child: _ZoomPill(zoom: viewState.zoom),
                ),
              ],
            ),
          ),
        );
      },
    );
  }

  void _handleTap(
    BuildContext context,
    FractalController controller,
    Offset localPosition,
  ) {
    final pan = MiniMapGeometry.panForTap(
      localPosition: localPosition,
      minimapSize: Size(size, size),
      zoom: controller.view.zoom,
    );

    controller.updatePan(vm.Vector2(pan.dx, pan.dy));
  }
}

class _ZoomIndicator extends StatelessWidget {
  final double zoom;
  const _ZoomIndicator({required this.zoom});

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
      decoration: BoxDecoration(
        color: Colors.black54,
        borderRadius: BorderRadius.circular(16),
      ),
      child: Text(
        'Zoom: ${zoom.toStringAsFixed(1)}×',
        style: const TextStyle(color: Colors.white, fontSize: 12),
      ),
    );
  }
}

class _ZoomPill extends StatelessWidget {
  final double zoom;
  const _ZoomPill({required this.zoom});

  @override
  Widget build(BuildContext context) {
    return Center(
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
        decoration: BoxDecoration(
          color: Colors.black87,
          borderRadius: BorderRadius.circular(8),
        ),
        child: Text(
          '${zoom.toStringAsFixed(0)}×',
          style: const TextStyle(color: Colors.white70, fontSize: 10),
        ),
      ),
    );
  }
}

class _GridPainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.white12
      ..strokeWidth = 0.5;

    // Draw grid
    for (var i = 1; i < 4; i++) {
      final x = size.width * i / 4;
      final y = size.height * i / 4;
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), paint);
      canvas.drawLine(Offset(0, y), Offset(size.width, y), paint);
    }
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => false;
}

class _ViewportPainter extends CustomPainter {
  final Offset pan;
  final double zoom;
  final Size viewportSize;

  _ViewportPainter({
    required this.pan,
    required this.zoom,
    required this.viewportSize,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.cyan
      ..style = PaintingStyle.stroke
      ..strokeWidth = 2;

    final rect = MiniMapGeometry.viewportRect(
      pan: pan,
      zoom: zoom,
      minimapSize: size,
      viewportSize: viewportSize,
    );

    canvas.drawRect(rect, paint);
  }

  @override
  bool shouldRepaint(covariant _ViewportPainter oldDelegate) {
    return pan != oldDelegate.pan ||
        zoom != oldDelegate.zoom ||
        viewportSize != oldDelegate.viewportSize;
  }
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';

/// Numeric bounds derived from a [FractalParameter] schema.
///
/// Integer schemas store bounds as doubles because they share the numeric
/// parameter contract with float sliders. [containsInteger] exposes the hidden
/// assumption that those double bounds still include at least one valid integer
/// value before integer rounding is applied.
final class FractalNumericParamBounds {
  const FractalNumericParamBounds({
    required this.min,
    required this.max,
  });

  factory FractalNumericParamBounds.fromSchema(FractalParameter schema) {
    return FractalNumericParamBounds(min: schema.min, max: schema.max);
  }

  final double min;
  final double max;

  bool get containsInteger => min.ceil() <= max.floor();

  double normalizeFloat(double value) => value.clamp(min, max).toDouble();

  int normalizeInteger(double value) {
    assert(
      containsInteger,
      'integer parameter bounds must include at least one integer value',
    );
    final rounded = normalizeFloat(value).round();
    if (!containsInteger) return rounded;
    return rounded.clamp(min.ceil(), max.floor()).toInt();
  }
}

/// Normalizes raw parameter values against a module parameter schema.
///
/// This keeps replayed state, presets, and direct UI updates on the same
/// contract: finite numeric values clamp to schema bounds after type coercion,
/// enum values must be one of the declared options, booleans must be real
/// booleans, and non-finite numeric values fall back to the schema default
/// instead of being promoted to an arbitrary bound.
Object normalizeFractalParamValue(FractalParameter schema, Object value) {
  if (schema.type == FractalParamType.boolean) {
    return value is bool ? value : _booleanDefault(schema);
  }
  if (schema.type == FractalParamType.enumeration) {
    final optionValues = schema.options.map((option) => option.value).toSet();
    return optionValues.contains(value) ? value : schema.defaultValue;
  }

  final numericValue = _finiteNumericValue(value);
  if (numericValue != null) {
    final bounds = FractalNumericParamBounds.fromSchema(schema);
    if (schema.type == FractalParamType.integer) {
      return bounds.normalizeInteger(numericValue);
    }
    return bounds.normalizeFloat(numericValue);
  }
  return schema.defaultValue;
}

double? _finiteNumericValue(Object value) {
  if (value is! num) return null;
  final numericValue = value.toDouble();
  return numericValue.isFinite ? numericValue : null;
}

bool _booleanDefault(FractalParameter schema) {
  final defaultValue = schema.defaultValue;
  return defaultValue is bool ? defaultValue : false;
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';
import 'package:flutter_test/flutter_test.dart';

String _label(_) => 'Parameter';

FractalParameter _booleanParam({required bool defaultValue}) {
  return FractalParameter(
    id: 'enabled',
    label: _label,
    type: FractalParamType.boolean,
    min: 0,
    max: 1,
    step: 1,
    defaultValue: defaultValue,
  );
}

FractalParameter _numericParam({
  required FractalParamType type,
  required Object defaultValue,
  double min = 1,
  double max = 10,
}) {
  return FractalParameter(
    id: 'value',
    label: _label,
    type: type,
    min: min,
    max: max,
    step: 1,
    defaultValue: defaultValue,
  );
}

void main() {
  group('normalizeFractalParamValue', () {
    test('preserves real boolean parameter values', () {
      final schema = _booleanParam(defaultValue: true);

      expect(normalizeFractalParamValue(schema, true), isTrue);
      expect(normalizeFractalParamValue(schema, false), isFalse);
    });

    test('falls back to boolean schema default for non-boolean values', () {
      expect(
        normalizeFractalParamValue(_booleanParam(defaultValue: true), 'true'),
        isTrue,
      );
      expect(
        normalizeFractalParamValue(_booleanParam(defaultValue: false), 1),
        isFalse,
      );
    });

    test('falls back to numeric schema default for non-finite numbers', () {
      final floatSchema = _numericParam(
        type: FractalParamType.float,
        defaultValue: 4.0,
      );
      final intSchema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
      );

      for (final candidate in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
      ]) {
        expect(
          normalizeFractalParamValue(floatSchema, candidate),
          4.0,
          reason: 'float candidate=$candidate',
        );
        expect(
          normalizeFractalParamValue(intSchema, candidate),
          4,
          reason: 'integer candidate=$candidate',
        );
      }
    });

    test('keeps rounded integer values inside fractional schema bounds', () {
      final schema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
        min: 1.2,
        max: 10.8,
      );
      final bounds = FractalNumericParamBounds.fromSchema(schema);

      expect(bounds.containsInteger, isTrue);
      expect(normalizeFractalParamValue(schema, 1.2), 2);
      expect(normalizeFractalParamValue(schema, 10.8), 10);
    });
  });
}

import 'dart:math';

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';

/// Generates one randomized value for a fractal parameter schema.
///
/// This pure helper keeps the controller's randomization data flow visible and
/// replayable in tests without depending on FractalController state. Returned
/// values are normalized through the same schema contract used for presets,
/// replayed state, and direct UI updates.
Object randomFractalParamValue(FractalParameter param, Random random) {
  switch (param.type) {
    case FractalParamType.float:
      final raw = param.min + random.nextDouble() * (param.max - param.min);
      return normalizeFractalParamValue(
        param,
        roundFractalParamValueToStep(raw, param.step),
      );
    case FractalParamType.integer:
      final bounds = FractalNumericParamBounds.fromSchema(param);
      assert(
        bounds.containsInteger,
        'integer parameter bounds must include at least one integer value',
      );
      if (!bounds.containsInteger) {
        return normalizeFractalParamValue(param, param.defaultValue);
      }
      final min = bounds.min.ceil();
      final max = bounds.max.floor();
      return normalizeFractalParamValue(
        param,
        min + random.nextInt(max - min + 1),
      );
    case FractalParamType.enumeration:
      if (param.options.isNotEmpty) {
        final choice = param.options[random.nextInt(param.options.length)];
        return choice.value;
      }
      return param.defaultValue;
    case FractalParamType.boolean:
      return random.nextBool();
  }
}

/// Snaps float randomization to slider step precision while avoiding typical
/// binary floating-point display noise.
double roundFractalParamValueToStep(double value, double step) {
  if (step <= 0) {
    return value;
  }
  final snapped = (value / step).round() * step;
  return double.parse(snapped.toStringAsFixed(6));
}

import 'dart:math';

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_randomizer.dart';
import 'package:flutter_test/flutter_test.dart';

String _label(_) => 'Parameter';

FractalParameter _numericParam({
  required FractalParamType type,
  required Object defaultValue,
  double min = 1.2,
  double max = 10.8,
}) {
  return FractalParameter(
    id: 'value',
    label: _label,
    type: type,
    min: min,
    max: max,
    step: 1,
    defaultValue: defaultValue,
  );
}

final class _FixedRandom implements Random {
  _FixedRandom({
    required this.nextIntValue,
    this.nextDoubleValue = 0.0,
  });

  final int Function(int max) nextIntValue;
  final double nextDoubleValue;

  @override
  int nextInt(int max) => nextIntValue(max);

  @override
  double nextDouble() => nextDoubleValue;

  @override
  bool nextBool() => false;
}

void main() {
  group('randomFractalParamValue', () {
    test('keeps integer random values inside fractional schema bounds', () {
      final schema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
      );

      expect(
        randomFractalParamValue(schema, _FixedRandom(nextIntValue: (_) => 0)),
        2,
      );
      expect(
        randomFractalParamValue(
          schema,
          _FixedRandom(nextIntValue: (max) => max - 1),
        ),
        10,
      );
    });

    test('normalizes stepped float random values back to schema bounds', () {
      final schema = _numericParam(
        type: FractalParamType.float,
        defaultValue: 4.0,
      );

      expect(
        randomFractalParamValue(schema, _FixedRandom(nextIntValue: (_) => 0)),
        1.2,
      );
      expect(
        randomFractalParamValue(
          schema,
          _FixedRandom(
            nextIntValue: (_) => 0,
            nextDoubleValue: 0.99,
          ),
        ),
        10.8,
      );
    });
  });
}

/// Pure bounds for effect inputs accepted by [FractalController].
///
/// Glow values are bounded shader-control inputs: finite values and infinities
/// clamp to explicit UI limits, while NaN falls back to the last known-good
/// value instead of being promoted to a maximum by [double.clamp].
/// Kaleidoscope rotation is intentionally unbounded, but shader uniforms still
/// need finite angles, so non-finite candidates preserve the last finite angle.
final class FractalEffectInputBounds {
  static const double minGlowSigma = 0.1;
  static const double maxGlowSigma = 5.0;
  static const double minGlowIntensity = 0.0;
  static const double maxGlowIntensity = 1.0;

  const FractalEffectInputBounds._();

  static double normalizeGlowSigma({
    required double candidate,
    required double current,
  }) {
    return _normalizeBounded(
      candidate: candidate,
      current: current,
      minValue: minGlowSigma,
      maxValue: maxGlowSigma,
    );
  }

  static double normalizeGlowIntensity({
    required double candidate,
    required double current,
  }) {
    return _normalizeBounded(
      candidate: candidate,
      current: current,
      minValue: minGlowIntensity,
      maxValue: maxGlowIntensity,
    );
  }

  static double normalizeKaleidoscopeRotation({
    required double candidate,
    required double current,
  }) {
    if (candidate.isFinite) return candidate;
    return current.isFinite ? current : 0.0;
  }

  static double _normalizeBounded({
    required double candidate,
    required double current,
    required double minValue,
    required double maxValue,
  }) {
    final fallback = current.isNaN ? minValue : current;
    if (candidate.isNaN) {
      return fallback.clamp(minValue, maxValue).toDouble();
    }
    return candidate.clamp(minValue, maxValue).toDouble();
  }
}

import 'package:flutter_fractals/features/renderer/providers/fractal_effect_input_bounds.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('FractalEffectInputBounds', () {
    test('preserves current bounded effect values when candidate is NaN', () {
      expect(
        FractalEffectInputBounds.normalizeGlowSigma(
          candidate: double.nan,
          current: 2.5,
        ),
        2.5,
      );
      expect(
        FractalEffectInputBounds.normalizeGlowIntensity(
          candidate: double.nan,
          current: 0.6,
        ),
        0.6,
      );
    });

    test('clamps finite and infinite bounded effect values', () {
      expect(
        FractalEffectInputBounds.normalizeGlowSigma(
          candidate: double.negativeInfinity,
          current: 2.5,
        ),
        FractalEffectInputBounds.minGlowSigma,
      );
      expect(
        FractalEffectInputBounds.normalizeGlowSigma(
          candidate: double.infinity,
          current: 2.5,
        ),
        FractalEffectInputBounds.maxGlowSigma,
      );
      expect(
        FractalEffectInputBounds.normalizeGlowIntensity(
          candidate: -0.5,
          current: 0.6,
        ),
        FractalEffectInputBounds.minGlowIntensity,
      );
      expect(
        FractalEffectInputBounds.normalizeGlowIntensity(
          candidate: 2.0,
          current: 0.6,
        ),
        FractalEffectInputBounds.maxGlowIntensity,
      );
    });

    test('preserves finite kaleidoscope rotation for non-finite candidates',
        () {
      expect(
        FractalEffectInputBounds.normalizeKaleidoscopeRotation(
          candidate: double.nan,
          current: 0.75,
        ),
        0.75,
