  double zy = py;

  const kAx = 0.42;
  const kAy = -0.18;
  const kBx = -0.31;
  const kBy = 0.24;
  const kCx = 0.73;
  const kCy = 0.11;
  const kDx = -0.26;
  const kDy = -0.39;
  const kEx = 0.85;
  const kEy = 0.07;

  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
