  Widget _buildCategoryBar(
    BuildContext context,
    AppLocalizations l10n, {
    required List<String> categories,
    required Map<String, int> categoryCounts,
  }) {
    if (categories.isEmpty) return const SizedBox.shrink();

    return Padding(
      padding: const EdgeInsets.fromLTRB(
        AppSpacing.lg,
        AppSpacing.xs,
        AppSpacing.lg,
        AppSpacing.xs,
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Text(
            l10n.catalogFilterCategories,
            style: AppTypography.labelSmall.copyWith(
              color: AppColors.textPrimary,
              fontWeight: FontWeight.w700,
              letterSpacing: 0.8,
            ),
          ),
          const SizedBox(height: AppSpacing.xs),
          SizedBox(
            height: 40,
            child: ListView.separated(
              key: const Key('catalogCategoryScroll'),
              scrollDirection: Axis.horizontal,
              itemCount: categories.length + 1,
              separatorBuilder: (_, __) => const SizedBox(width: AppSpacing.xs),
              itemBuilder: (context, index) {
                if (index == 0) {
                  return _DimChip(
                    chipKey: const Key('catalogCategoryChip_all'),
                    label: l10n.catalogFilterAll,
                    count: _entriesForCategoryCounts(l10n).length,
                    selected: _selectedCategory == null,
                    onTap: () {
                      setState(() {
                        _selectedCategory = null;
                      });
                    },
                  );
                }

                final category = categories[index - 1];
                return _DimChip(
                  chipKey: Key(
                    'catalogCategoryChip_${_keySegment(category)}',
                  ),
                  label: category,
                  count: categoryCounts[category] ?? 0,
                  selected: _selectedCategory == category,
                  onTap: () {
                    setState(() {
                      _selectedCategory =
                          _selectedCategory == category ? null : category;
                    });
                  },
                );
              },
            ),
          ),
        ],
      ),
    );
  }

